  "requestNumber",
  "packetNumber",
  "appointmentNumber",
  "assignmentNumber",
  "historyNumber",
  "escalationNumber",
  "noteNumber",
  "outcomeNumber",
  "revenueNumber",
  "dispatchNumber",
  "deliveryNumber",
  "sessionNumber",
  "actionId",
  "encounterId",
  "intakeId",
  "appointmentId",
  "providerAssignmentId",
  "videoSessionId",
  "lifecycleState",
  "linkedRecordCounts",
  "consentCount",
  "vitalsCount",
  "noteCount",
  "referralCount",
  "followUpCount",
  "outcomeCount",
  "emergencyEscalationCount",
  "historyCount",
  "prescriptionPacketCount",
  "providerActionCount",
  "latestProviderAction",
